mapper.select:
SELECT t1.slide_id, t1.image_id, t2.image_url, t2.image_path FROM fr_slide t1 LEFT JOIN tb_image t2 ON t1.image_id = t2.image_id
AND t1.special_id = #{specialId}
AND t1.process_flag = #{processFlag}
AND t1.analyze_status = #{analyzeStatus}
AND t1.slide_id in
#{item}
ORDER BY t1.create_time ASC

select fs.slide_id,fs.wax_code
from fr_slide fs
         left join fr_special fsl on fs.special_id = fsl.special_id
where fsl.topic_id= #{topicId}
  and fsl.species_id= #{speciesId}
  and fsl.del_flag='0'

SELECT ti.image_name, ti.image_url, ti.image_id, ss.single_id, ss.slide_id, ss.thumb_url, ss.category_id, ss.forecast_status, ss.diagnosis_status, ss.description, fc.organ_en, fc.organ_name, fs.group_code, fs.wax_code, fs.animal_code, fs.gender_flag, fs.initiate_by, ss.create_time FROM fr_single_slide ss LEFT JOIN fr_slide fs ON ss.slide_id = fs.slide_id LEFT JOIN fr_category fc ON ss.category_id = fc.category_id left join tb_image ti on fs.image_id = ti.image_id
fs.special_id = #{specialId}
and ti.image_name like concat('%',#{imageName},'%')
and fs.animal_code like concat('%',#{animalCode},'%')
and ss.category_id =#{categoryId}
and fs.group_code like concat('%',#{groupCode},'%')
and ss.category_id =#{categoryId}
and ss.forecast_status =#{forecastStatus}
AND ss.forecast_status in
#{item}
and ss.diagnosis_status =#{diagnosisStatus}
AND date_format( ss.create_time,'%Y%m%d') >= date_format(#{createTimeParams.beginTime},'%Y%m%d')
AND date_format( ss.create_time,'%Y%m%d') <= date_format(#{createTimeParams.endTime},'%Y%m%d')
order by ${sortField} ${sortType}
order by ss.create_time desc

SELECT ti.image_name, ss.single_id, ss.slide_id, ss.thumb_url, ss.category_id, ss.forecast_status, ss.diagnosis_status, ss.description, fc.organ_en, fc.organ_name, fs.group_code, fs.wax_code, fs.animal_code, fs.gender_flag, fs.initiate_by, ss.create_time FROM fr_single_slide ss LEFT JOIN fr_slide fs ON ss.slide_id = fs.slide_id LEFT JOIN fr_category fc ON ss.category_id = fc.category_id left join tb_image ti on fs.image_id = ti.image_id
fs.special_id = #{specialId}
and ti.image_name like concat('%',#{imageName},'%')
and fs.animal_code like concat('%',#{animalCode},'%')
and ss.category_id =#{categoryId}
and fs.group_code like concat('%',#{groupCode},'%')
and ss.category_id =#{categoryId}
and ss.forecast_status =#{forecastStatus}
and ss.diagnosis_status =#{diagnosisStatus}
AND date_format( ss.create_time,'%Y%m%d') >= date_format(#{createTimeParams.beginTime},'%Y%m%d')
AND date_format( ss.create_time,'%Y%m%d') <= date_format(#{createTimeParams.endTime},'%Y%m%d')
order by ${sortField} ${sortType}
order by ss.create_time desc

SELECT ti.image_name, ss.single_id, ss.single_id as singleSlideId, ss.slide_id, ss.thumb_url, ss.category_id, ss.forecast_status, ss.diagnosis_status, ss.description, fc.organ_en, fc.organ_name, fs.group_code, fs.wax_code, fs.animal_code, fs.gender_flag, fs.initiate_by, ss.create_time, ti.*, ti.thumb_url as imageThumbUrl, fs.special_id FROM fr_single_slide ss LEFT JOIN fr_slide fs ON ss.slide_id = fs.slide_id LEFT JOIN fr_category fc ON ss.category_id = fc.category_id left join tb_image ti on fs.image_id = ti.image_id
fs.special_id = #{specialId}
and ti.image_name like concat('%',#{imageName},'%')
and fs.animal_code like concat('%',#{animalCode},'%')
and ss.category_id =#{categoryId}
and fs.group_code like concat('%',#{groupCode},'%')
and ss.category_id =#{categoryId}
and ss.forecast_status =#{forecastStatus}
and ss.diagnosis_status =#{diagnosisStatus}
AND date_format( ss.create_time,'%Y%m%d') >= date_format(#{createTimeParams.beginTime},'%Y%m%d')
AND date_format( ss.create_time,'%Y%m%d') <= date_format(#{createTimeParams.endTime},'%Y%m%d')
order by #{sortField} #{sortOrder}
order by ss.create_time desc
